#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a, b;
        scanf("%d %d", &a, &b);
        if ((a + b) % 2) {
            printf("Alice\n");
        } else {
            printf("Bob\n");
        }
    }
    return 0;
}

